`Approach 2: Sign Adjustment Using Absolute ValueAn alternative method is to handle the sign of NNN separately:


When NNN is negative and XXX is odd, then NXN^XNX is negative.
When NNN is negative and XXX is even, NXN^XNX becomes positive because the negative sign cancels out.
Thus, we compute the power using the absolute value of NNN and then, if necessary, adjust the sign of the final result.

`#include &lt;iostream&gt;
#include &lt;cstdlib&gt; // For abs
using namespace std;

long long mod_pow_abs(long long base, long long exp, long long mod) {
    long long result = 1;
    base = abs(base);
    while(exp &gt; 0) {
        if(exp % 2 == 1) {
            result = (result * base) % mod;
        }
        base = (base * base) % mod;
        exp /= 2;
    }
    return result;
}

int main() {
    int T;
    cin &gt;&gt; T;
    while(T--) {
        long long N, X, M;
        cin &gt;&gt; N &gt;&gt; X &gt;&gt; M;
        long long power_value;
        if(X == 0) {
            power_value = 1;
        } else if(N &lt; 0 &amp;&amp; X % 2 == 1) {
            power_value = -mod_pow_abs(N, X, M);
        } else {
            power_value = mod_pow_abs(N, X, M);
        }
        cout &lt;&lt; power_value &lt;&lt; "\n";
    }
    return 0;
}
